+        // Check if start state is a match state
+        if (self.states.items[current_state].is_match) {
+            match_end = start;
+        }
+
+        var pos = start;
+        while (pos < text.len) : (pos += 1) {
+            const c = text[pos];
+
+            // Get or build transition
+            const next_state = try self.getTransition(current_state, c);
