+            if (next_state == DEAD_STATE) {
+                // No more matches possible
+                break;
+            }
+
+            current_state = next_state;
+
+            // Check if this is a match state
+            if (self.states.items[current_state].is_match) {
+                match_end = pos + 1; // Greedy: keep updating
+            }
