-                    i += 1;
-                    j += prefixModifier(patt, j, RegOp{ .eager_plus = {} }) catch {
-                        bad_string = true;
-                        break :dispatch;
-                    };
-                } else {
-                    j += prefixModifier(patt, j, RegOp{ .plus = {} }) catch {
-                        bad_string = true;
-                        break :dispatch;
-                    };
-                }
-            },
-            '{' => { // {M,N} etc, or just character literal is fine
-                i += 1;
-                if (in[i] == ',') { // {,?
-                    i += 1;
-                    const d, const c1 = parseByte(in[i..]) catch {
-                        bad_string = true;
-                        break :dispatch;
-                    };
-                    i += d;
-                    if (in[i] == '}') { // {,N}
