-                            bad_string = true;
-                            break :dispatch;
-                        };
-                        j += 1;
-                        j += prefixModifier(patt, j, RegOp{ .some = c1 }) catch {
-                            bad_string = true;
-                            break :dispatch;
-                        };
-                        continue :dispatch;
