-                            bad_string = true;
-                            break :dispatch;
-                        };
-                        i += 1;
-                    } else {
-                        j += prefixModifier(patt, j, RegOp{ .up_to = c_rest }) catch {
-                            bad_string = true;
-                            break :dispatch;
-                        };
-                    }
-                    j += 1;
-                    j += prefixModifier(patt, j, RegOp{ .some = c1 }) catch {
-                        bad_string = true;
-                        break :dispatch;
-                    };
