-    }
-    if (pump != 0) {
-        logError("missing closing parenthesis\n", .{});
-        return null;
-    }
-    if (bad_string) {
-        const tail = switch (i) {
-            0 => "st",
-            1 => "nd",
-            2 => "rd",
-            else => "th",
-        };
