-// Special set masks
-const d_MASK: u64 = 0x03ff000000000000; // low
-const w_HI_MASK: u64 = 0x07fffffe87fffffe;
-const w_LOW_MASK = d_MASK;
-const s_MASK: u64 = 0x0000000100003e00; // low
-const ALL_MASK: u64 = ~@as(u64, 0);
