+                try self.epsilonClosure(result, target);
+            }
+        }
+    }
+
+    /// Check if a set of NFA states contains the match state
+    fn containsMatchState(self: *LazyDFA, states: []const StateId) bool {
+        _ = self;
+        for (states) |state| {
+            if (state == MATCH_STATE) return true;
+        }
+        return false;
+    }
+};

