+    fn parseNumber(self: *Parser) ParseError!usize {
+        var num: usize = 0;
+        var found = false;
+
+        while (self.peek()) |c| {
+            if (c < '0' or c > '9') break;
+            found = true;
+            num = num * 10 + (c - '0');
+            self.advance();
+        }
+
+        if (!found) return error.InvalidRepeat;
+        return num;
+    }
