+    var nfa_instance = try builder.build(expr);
+    defer nfa_instance.deinit();
+
+    // Test non-matching
+    var vm = PikeVM.init(allocator, &nfa_instance);
+
+    const result = try vm.find("b");
+    try std.testing.expect(result == null);
+}

