+    fn addSpecialToken(self: *WordPiece, token: []const u8, id: u32) !void {
+        const owned = try self.allocator.dupe(u8, token);
+        try self.vocab.put(owned, id);
+        try self.vocab_r.put(id, owned);
+    }
